external_knowledge:
- "mishaps" refers to injuries;
- "usual number of mishaps" refers to the average number of injuries across all patients;
- "from the most injured to the least" means sorted in descending order of injury count.

sql:
SELECT patients.first_name, patients.last_name, injuries.injury_description
FROM patients
JOIN injuries ON patients.patient_id = injuries.patient_id;

SELECT COUNT(*)
FROM nexus_scores
WHERE score = 'None';

SELECT first_name AS name, email FROM patients
UNION
SELECT staff_name AS name, email FROM medical_staff;

SELECT DISTINCT ms.staff_name
FROM medical_staff ms
JOIN nexus_scores ns ON ms.staff_id = ns.staff_id;
